const { input, criteria = ['correctness', 'completeness', 'conciseness'], max_iterations = 3 } = $json;
return {
  input,
  criteria,
  max_iterations,
  max_safe_iterations: Math.min(max_iterations, 10),
  iteration: 0,
  history: [],
  best_output: null,
  best_score: 0
};

const state = $json;
state.iteration++;
state.history.push({
  iteration: state.iteration,
  output: state.current_output || state.input,
  timestamp: new Date().toISOString()
});
return state;

const state = $json;
const current = state.history[state.history.length - 1];
const evaluations = {};
let totalScore = 0;
state.criteria.forEach(c => {
  const score = Math.min(10, Math.max(1, Math.round(Math.random() * 6 + 4)));
  evaluations[c] = { score, max: 10 };
  totalScore += score;
});
const avgScore = totalScore / state.criteria.length;
state.evaluations = evaluations;
state.avg_score = avgScore;
if (avgScore > state.best_score) {
  state.best_score = avgScore;
  state.best_output = current.output;
}
return state;

const state = $json;
const lastEval = state.evaluations || {};
const weakAreas = Object.entries(lastEval)
  .filter(([k, v]) => v.score < 7)
  .map(([k]) => k);
state.improvement_focus = weakAreas.length > 0
  ? `Improve: ${weakAreas.join(', ')}`
  : 'Polish and refine';
return state;

const state = $json;
return {
  input: state.input,
  best_output: state.best_output || state.history[state.history.length - 1]?.output,
  best_score: state.best_score,
  iterations_run: state.iteration,
  max_safe_iterations: state.max_safe_iterations,
  evaluation_history: state.history.map(h => ({
    iteration: h.iteration,
    score: state.avg_score
  })),
  converged: state.best_score >= 8,
  circuit_breaker: state.iteration >= state.max_safe_iterations,
  summary: `Completed ${state.iteration}/${state.max_safe_iterations} iterations. Best score: ${state.best_score.toFixed(1)}/10. ${state.best_score >= 8 ? 'Converged.' : state.iteration >= state.max_safe_iterations ? 'Circuit breaker triggered.' : 'Manual review recommended.'}`
};
